-- Marcas como variantes en items K37 (Whale se deja en el nombre)
BEGIN;
update panol_materiales set variantes='[]'::jsonb where origen='k37_enero2026';
update panol_materiales set variantes = variantes || '["Samsung"]'::jsonb where origen='k37_enero2026' and descripcion ~* '\mSamsung\M' and not (variantes @> '["Samsung"]');
