update panol_materiales set variantes = variantes || '["Shakespeare"]'::jsonb where origen='k37_enero2026' and descripcion ~* '\mShakespeare\M' and not (variantes @> '["Shakespeare"]');
update panol_materiales set variantes = variantes || '["Bidematic"]'::jsonb where origen='k37_enero2026' and descripcion ~* '\mBidematic\M' and not (variantes @> '["Bidematic"]');
