update panol_materiales set descripcion = regexp_replace(descripcion, '\s*/?\mSamsung\M', '', 'gi') where origen='k37_enero2026' and descripcion ~* '\mSamsung\M';
update panol_materiales set descripcion = regexp_replace(descripcion, '\s*/?\mLG\M', '', 'gi') where origen='k37_enero2026' and descripcion ~* '\mLG\M';
update panol_materiales set descripcion = regexp_replace(descripcion, '\s*/?\mWema\M', '', 'gi') where origen='k37_enero2026' and descripcion ~* '\mWema\M';
update panol_materiales set descripcion = regexp_replace(descripcion, '\s*/?\mCentek\M', '', 'gi') where origen='k37_enero2026' and descripcion ~* '\mCentek\M';
update panol_materiales set descripcion = regexp_replace(descripcion, '\s*/?u-flex', '', 'gi') where origen='k37_enero2026' and descripcion ~* 'u-flex';
update panol_materiales set descripcion = regexp_replace(descripcion, '\s*/?\mBennett\M', '', 'gi') where origen='k37_enero2026' and descripcion ~* '\mBennett\M';
