update panol_materiales set descripcion = regexp_replace(descripcion, '\s*/?\mPerko\M', '', 'gi') where origen='k37_enero2026' and descripcion ~* '\mPerko\M';
update panol_materiales set descripcion = regexp_replace(descripcion, '\s*/?\mKallay\M', '', 'gi') where origen='k37_enero2026' and descripcion ~* '\mKallay\M';
update panol_materiales set descripcion = regexp_replace(descripcion, '\s*/?\mHafele\M', '', 'gi') where origen='k37_enero2026' and descripcion ~* '\mHafele\M';
update panol_materiales set descripcion = regexp_replace(descripcion, '\s*/?\mThreebond\M', '', 'gi') where origen='k37_enero2026' and descripcion ~* '\mThreebond\M';
update panol_materiales set descripcion = regexp_replace(descripcion, '\s*/?\mWhirpool\M', '', 'gi') where origen='k37_enero2026' and descripcion ~* '\mWhirpool\M';
update panol_materiales set descripcion = regexp_replace(descripcion, '\s*/?\mAtma\M', '', 'gi') where origen='k37_enero2026' and descripcion ~* '\mAtma\M';
update panol_materiales set descripcion = regexp_replace(descripcion, '\s*/?u-line', '', 'gi') where origen='k37_enero2026' and descripcion ~* 'u-line';
update panol_materiales set descripcion = regexp_replace(descripcion, '\s*/?\mShakespeare\M', '', 'gi') where origen='k37_enero2026' and descripcion ~* '\mShakespeare\M';
update panol_materiales set descripcion = regexp_replace(descripcion, '\s*/?\mBidematic\M', '', 'gi') where origen='k37_enero2026' and descripcion ~* '\mBidematic\M';
