update panol_materiales set descripcion = regexp_replace(descripcion, '\s*/?\mLofrans\M', '', 'gi') where origen='k37_enero2026' and descripcion ~* '\mLofrans\M';
update panol_materiales set descripcion = btrim(regexp_replace(descripcion, '\s{2,}', ' ', 'g'), ' /,-') where origen='k37_enero2026';
COMMIT;
